func newDoctorCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "doctor",
		Short: "Check CLI health",
		RunE: func(cmd *cobra.Command, args []string) error {
			report := map[string]any{}

			// Check config
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				report["config"] = fmt.Sprintf("error: %s", err)
			} else {
				report["config"] = "ok"
				report["config_path"] = cfg.Path
				report["base_url"] = cfg.BaseURL
			}

			// Check auth
			if cfg != nil {
				header := cfg.AuthHeader()
				if header == "" {
					report["auth"] = "not configured"
					report["auth_hint"] = "export HAPPENSTANCE_WEB_APP_COOKIE_AUTH=<your-key>"
				} else {
					report["auth"] = "configured"
					report["auth_source"] = cfg.AuthSource
				}
			}

			// Check auth environment variables
			authEnvChecked := 0
			authEnvSet := 0
			authEnvChecked++
			if os.Getenv("HAPPENSTANCE_WEB_APP_COOKIE_AUTH") != "" {
				authEnvSet++
			}
			if authEnvSet == 0 {
				report["env_vars"] = fmt.Sprintf("none set (checked %d)", authEnvChecked)
			} else {
				report["env_vars"] = fmt.Sprintf("%d/%d set", authEnvSet, authEnvChecked)
			}

			// Check API connectivity and validate credentials
			if cfg != nil && cfg.BaseURL != "" {
				httpClient := &http.Client{Timeout: 5 * time.Second}
				baseURL := strings.TrimRight(cfg.BaseURL, "/")

				// Step 1: Basic reachability (unauthenticated HEAD)
				headReq, _ := http.NewRequest("HEAD", baseURL, nil)
				headResp, headErr := httpClient.Do(headReq)
				apiReachable := false
				if headErr == nil {
					headResp.Body.Close()
					apiReachable = true
				}

				// If HEAD failed, try GET on common health endpoints
				if !apiReachable {
					for _, p := range []string{"/health", "/healthz", "/status", "/ping", ""} {
						healthResp, healthErr := httpClient.Get(baseURL + p)
						if healthErr != nil {
							continue
						}
						healthResp.Body.Close()
						apiReachable = true
						break
					}
				}

				if !apiReachable {
					report["api"] = fmt.Sprintf("unreachable: %s", headErr)
				} else {
					report["api"] = "reachable"
				}

				// Step 2: Validate credentials with an authenticated request
				authHeader := cfg.AuthHeader()
				if authHeader == "" {
					// No auth configured — skip credential validation
				} else if !apiReachable {
					report["credentials"] = "skipped (API unreachable)"
				} else {
					authReq, _ := http.NewRequest("GET", baseURL, nil)
					authReq.Header.Set("__session", authHeader)
					authReq.Header.Set("User-Agent", "contact-goat-pp-cli")
					authResp, authErr := httpClient.Do(authReq)
					if authErr != nil {
						report["credentials"] = "error: could not reach API"
					} else {
						authResp.Body.Close()
						switch {
						case authResp.StatusCode >= 200 && authResp.StatusCode < 300:
							report["credentials"] = "valid"
						case authResp.StatusCode == 401 || authResp.StatusCode == 403:
							report["credentials"] = fmt.Sprintf("invalid (HTTP %d) — check your credentials", authResp.StatusCode)
						default:
							// Non-auth HTTP error (404, 500, etc.) — don't blame credentials
							report["credentials"] = fmt.Sprintf("ok (HTTP %d from base URL, but auth was accepted)", authResp.StatusCode)
						}
					}
				}
			} else if cfg != nil && cfg.BaseURL == "" {
				report["api"] = "not configured (set base_url in config file)"
			}

			// Happenstance cookie-auth section
			checkHappenstance(report)
			checkHappenstanceGraphCoverage(flags, report)

			// LinkedIn MCP section (Python / uvx / profile)
			checkLinkedIn(report)

			// Deepline section (env var presence, dlp_ prefix, CLI on PATH)
			checkDeepline(report)

			report["version"] = version

			if flags.asJSON {
				return flags.printJSON(cmd, report)
			}

			// Human-readable output with color
			w := cmd.OutOrStdout()
			checkKeys := []struct{ key, label string }{
				{"config", "Config"},
				{"auth", "Auth"},
				{"api", "API"},
				{"credentials", "Credentials"},
				{"happenstance_cookies", "Happenstance: cookies"},
				{"happenstance_session", "Happenstance: session JWT"},
				{"happenstance_graph", "Happenstance: graph coverage"},
				{"linkedin_python", "LinkedIn: Python"},
				{"linkedin_uvx", "LinkedIn: uvx"},
				{"linkedin_binary", "LinkedIn: binary"},
				{"linkedin_profile", "LinkedIn: profile"},
				{"deepline_env", "Deepline: DEEPLINE_API_KEY"},
				{"deepline_prefix", "Deepline: key prefix"},
				{"deepline_cli", "Deepline: CLI on PATH"},
			}
			for _, ck := range checkKeys {
				v, ok := report[ck.key]
				if !ok {
					continue
				}
				s := fmt.Sprintf("%v", v)
				indicator := green("OK")
				if strings.Contains(s, "error") || strings.Contains(s, "not configured") || strings.Contains(s, "unreachable") || strings.Contains(s, "invalid") {
					indicator = red("FAIL")
				} else if strings.Contains(s, "not ") || strings.Contains(s, "skipped") || strings.Contains(s, "inferred") {
					indicator = yellow("WARN")
				}
				fmt.Fprintf(w, "  %s %s: %s\n", indicator, ck.label, s)
			}
			// Print info keys without status indicator
			for _, key := range []string{"config_path", "base_url", "auth_source", "version"} {
				if v, ok := report[key]; ok {
					fmt.Fprintf(w, "  %s: %v\n", key, v)
				}
			}
			// Print auth setup hints (indented under Auth line)
			if hint, ok := report["auth_hint"]; ok {
				fmt.Fprintf(w, "  hint: %v\n", hint)
			}
			if hint, ok := report["happenstance_hint"]; ok {
				fmt.Fprintf(w, "  hint: %v\n", hint)
			}
			if hint, ok := report["deepline_hint"]; ok {
				fmt.Fprintf(w, "  hint: %v\n", hint)
			}
			return nil
		},
	}
}

// checkHappenstance populates doctor's Happenstance cookie-auth fields. We
// NEVER print the JWT, the cookie values, or anything beyond expiry status
// and cookie names.
func checkHappenstance(report map[string]any) {
	path, err := chromecookies.DefaultCookieFilePath(appConfigDir, "happenstance")
	if err != nil {
		report["happenstance_cookies"] = fmt.Sprintf("error: %s", err)
		return
	}
	cf, err := chromecookies.ReadCookieFile(path)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			report["happenstance_cookies"] = "not configured"
			report["happenstance_hint"] = "run: contact-goat-pp-cli auth login --chrome --service happenstance"
			return
		}
		report["happenstance_cookies"] = fmt.Sprintf("error: %s", err)
		return
	}
	report["happenstance_cookies"] = fmt.Sprintf("found: %d cookies (%s)", len(cf.Cookies), path)

	// Check __session JWT expiry without printing it.
	var jwt string
	for _, ck := range cf.Cookies {
		if ck.Name == "__session" {
			jwt = ck.Value
			break
		}
	}
	if jwt == "" {
		report["happenstance_session"] = "not found in cookie file (missing __session)"
		return
	}
	if client.IsJWTExpired(jwt) {
		report["happenstance_session"] = "expired or <10s from expiry (will refresh on next request)"
	} else {
		report["happenstance_session"] = "valid"
	}
}

// checkHappenstanceGraphCoverage hits /api/uploads/status/user to
// report how the user's synced data sources look. Surfaces when the
// LinkedIn CSV import last refreshed so users know the 1st-degree
// graph freshness and can re-upload if it is stale. Best-effort: any
// error here is non-fatal and produces a concise "status unknown" line.
func checkHappenstanceGraphCoverage(flags *rootFlags, report map[string]any) {
	if _, ok := report["happenstance_session"]; !ok {
		return // no cookies, skip
	}
	c, err := flags.newClientRequireCookies("happenstance")
	if err != nil {
		report["happenstance_graph"] = "unavailable (cookies not loaded)"
		return
	}
	// Refresh the session before making the authenticated call; doctor
	// is specifically the place people run to diagnose auth, so making
	// that refresh path exercised here is the point.
	if refErr := c.MaybeRefreshSession(); refErr != nil {
		report["happenstance_graph"] = fmt.Sprintf("session refresh failed: %s", trimErr(refErr.Error()))
		report["happenstance_session"] = fmt.Sprintf("expired; refresh FAILED: %s", trimErr(refErr.Error()))
		return
	}
	raw, err := c.Get("/api/uploads/status/user", nil)
	if err != nil {
		report["happenstance_graph"] = fmt.Sprintf("unavailable: %s", trimErr(err.Error()))
		return
	}
	if len(raw) == 0 {
		// Empty body on an authenticated endpoint is Clerk's
		// signed-out signal. It means the refresh above returned 200
		// but didn't actually hand us a fresh JWT — usually because
		// the source cookies are stale. Say so plainly; the previous
		// phrasing ("authenticated but …") was misleading.
		report["happenstance_graph"] = "signed-out (empty body on authenticated endpoint — session is dead, re-run `auth login --chrome` against a signed-in browser)"
		return
	}
	var resp struct {
		Statuses struct {
			LinkedInExt []struct {
				Status         string `json:"status"`
				IsActive       bool   `json:"isActive"`
				IsError        bool   `json:"isError"`
				LastRefreshed  string `json:"last_refreshed"`
				Timestamp      string `json:"timestamp"`
			} `json:"linkedin_ext"`
		} `json:"statuses"`
		HasAnyUploads       bool `json:"hasAnyUploads"`
		ActiveAccountsCount int  `json:"activeAccountsCount"`
	}
	if err := jsonUnmarshal(raw, &resp); err != nil {
		report["happenstance_graph"] = fmt.Sprintf("decode failed: %s", trimErr(err.Error()))
		return
	}
	if len(resp.Statuses.LinkedInExt) == 0 {
		report["happenstance_graph"] = "no LinkedIn contacts synced yet (upload at happenstance.ai/integrations)"
		return
	}
	entry := resp.Statuses.LinkedInExt[0]
	age := ""
	if ts, err := time.Parse(time.RFC3339, entry.LastRefreshed); err == nil {
		age = fmt.Sprintf(" (%s ago)", humanAge(time.Since(ts)))
	}
	status := entry.Status
	if entry.IsError {
		status = "ERROR"
	}
	report["happenstance_graph"] = fmt.Sprintf("linkedin_ext: %s, last refreshed %s%s",
		status, fallbackStr(entry.LastRefreshed, "unknown"), age)
}

func trimErr(s string) string {
	if len(s) > 120 {
		return s[:120] + "..."
	}
	return s
}

func fallbackStr(s, def string) string {
	if strings.TrimSpace(s) == "" {
		return def
	}
	return s
}

func humanAge(d time.Duration) string {
	days := int(d.Hours() / 24)
	if days < 1 {
		h := int(d.Hours())
		if h < 1 {
			return fmt.Sprintf("%dm", int(d.Minutes()))
		}
		return fmt.Sprintf("%dh", h)
	}
	if days < 60 {
		return fmt.Sprintf("%dd", days)
	}
	months := days / 30
	return fmt.Sprintf("%dmo", months)
}

// jsonUnmarshal is a thin wrapper to keep the local helper name
// consistent with other check* helpers in this file.
func jsonUnmarshal(data []byte, v any) error {
	return json.Unmarshal(data, v)
}

// checkDeepline populates doctor's Deepline fields. We NEVER echo the API
// key value: only "set"/"not set", the prefix validity, and whether the
// official CLI is on PATH (informational, not required).
func checkDeepline(report map[string]any) {
	key := os.Getenv("DEEPLINE_API_KEY")
	if key == "" {
		report["deepline_env"] = "not set"
		report["deepline_hint"] = "export DEEPLINE_API_KEY=dlp_... (Deepline CLI falls back to HTTP when the `deepline` binary isn't on PATH)"
	} else {
		report["deepline_env"] = "set"
		if strings.HasPrefix(key, "dlp_") {
			report["deepline_prefix"] = "ok (dlp_)"
		} else if strings.HasPrefix(key, "dpl_") {
			report["deepline_prefix"] = `invalid — "dpl_" is a Vercel prefix, not Deepline`
		} else {
			report["deepline_prefix"] = `invalid — Deepline keys start with "dlp_"`
		}
	}

	// Informational: is the official CLI on PATH? Not required — we have
	// an HTTP fallback.
	if path, err := exec.LookPath("deepline"); err == nil {
		report["deepline_cli"] = fmt.Sprintf("found: %s", path)
	} else {
		report["deepline_cli"] = "not found (HTTP fallback will be used)"
	}
}
